import pygame
import random
from constants import GRID_SIZE, GRID_WIDTH, GRID_HEIGHT, RED

class Food:
    def __init__(self):
        self.position = (0, 0)
        self.randomize_position()

    def randomize_position(self, occupied_positions=None):
        if occupied_positions is None:
            occupied_positions = []
        while True:
            x = random.randint(0, GRID_WIDTH - 1)
            y = random.randint(0, GRID_HEIGHT - 1)
            if (x, y) not in occupied_positions:
                self.position = (x, y)
                break

    def draw(self, screen):
        x, y = self.position
        rect = pygame.Rect(x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE)
        pygame.draw.rect(screen, RED, rect)

import pygame
from collections import deque
import random
from constants import GRID_SIZE, GRID_WIDTH, GRID_HEIGHT, GREEN, BLACK, WHITE

class Snake:
    def __init__(self):
        self.body = deque()
        self.head_x = GRID_WIDTH // 2
        self.head_y = GRID_HEIGHT // 2
        self.body.append((self.head_x, self.head_y))
        self.direction = (1, 0)  # (dx, dy) - initial direction: right
        self.grow_pending = False

    def move(self):
        self.head_x += self.direction[0]
        self.head_y += self.direction[1]

        new_head = (self.head_x, self.head_y)

        # Check for self-collision before adding new head
        if new_head in self.body:
            return False # Game over

        self.body.appendleft(new_head) # Add new head to the front

        if self.grow_pending:
            self.grow_pending = False
        else:
            self.body.pop() # Remove tail if not growing

        return True # Snake moved successfully

    def grow(self):
        self.grow_pending = True

    def change_direction(self, new_dir):
        # Prevent reversing direction immediately
        if (new_dir[0] * -1, new_dir[1] * -1) != self.direction:
            self.direction = new_dir

    def check_collision(self):
        # Wall collision
        if not (0 <= self.head_x < GRID_WIDTH and 0 <= self.head_y < GRID_HEIGHT):
            return True
        # Self collision (checked in move method)
        return False

    def get_head_position(self):
        return (self.head_x, self.head_y)

    def get_body(self):
        return list(self.body)

    def draw(self, screen):
        for i, segment in enumerate(self.body):
            x, y = segment
            rect = pygame.Rect(x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE)
            if i == 0: # Head
                pygame.draw.rect(screen, GREEN, rect)
                pygame.draw.rect(screen, BLACK, rect, 2) # Border for head
            else:
                pygame.draw.rect(screen, GREEN, rect)

const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

let W, H;

function resizeCanvas() {
    W = canvas.width = window.innerWidth * 0.8; // Make canvas 80% of window width
    H = canvas.height = window.innerHeight * 0.8; // Make canvas 80% of window height
}

window.addEventListener('resize', resizeCanvas);
resizeCanvas(); // Initial resize

// --- Game State ---
const player = {
    x: W / 2,
    y: H / 2,
    size: 20,
    color: 'rgba(255, 255, 255, 0.8)',
    speed: 5,
    vx: 0,
    vy: 0,
    maxSpeed: 8,
    friction: 0.9, // How much velocity decays each frame
    acceleration: 0.5,
    trail: [],
    trailLength: 20,
    trailColor: 'rgba(100, 150, 255, 0.5)',
};

const keys = {};
window.addEventListener('keydown', (e) => {
    keys[e.key] = true;
});
window.addEventListener('keyup', (e) => {
    keys[e.key] = false;
});

// --- Particles (Stars) ---
const particles = [];
const numParticles = 100;

function createParticles() {
    for (let i = 0; i < numParticles; i++) {
        particles.push({
            x: Math.random() * W,
            y: Math.random() * H,
            size: Math.random() * 2 + 0.5,
            color: `rgba(255, 255, 255, ${Math.random() * 0.5 + 0.3})`,
            speed: Math.random() * 0.5 + 0.1,
            direction: Math.random() * Math.PI * 2, // 0 to 2PI
            driftX: (Math.random() - 0.5) * 0.2, // Subtle horizontal drift
            driftY: (Math.random() - 0.5) * 0.2, // Subtle vertical drift
            opacity: Math.random() * 0.5 + 0.3,
            blinkTimer: Math.random() * 100,
        });
    }
}

// --- Game Loop ---
function update() {
    // Player movement
    let targetVx = 0;
    let targetVy = 0;

    if (keys['ArrowUp'] || keys['w']) targetVy -= player.acceleration;
    if (keys['ArrowDown'] || keys['s']) targetVy += player.acceleration;
    if (keys['ArrowLeft'] || keys['a']) targetVx -= player.acceleration;
    if (keys['ArrowRight'] || keys['d']) targetVx += player.acceleration;

    player.vx += targetVx;
    player.vy += targetVy;

    // Apply friction
    player.vx *= player.friction;
    player.vy *= player.friction;

    // Limit speed
    const currentSpeed = Math.sqrt(player.vx * player.vx + player.vy * player.vy);
    if (currentSpeed > player.maxSpeed) {
        player.vx = (player.vx / currentSpeed) * player.maxSpeed;
        player.vy = (player.vy / currentSpeed) * player.maxSpeed;
    }

    player.x += player.vx;
    player.y += player.vy;

    // Keep player within canvas bounds
    player.x = Math.max(player.size / 2, Math.min(W - player.size / 2, player.x));
    player.y = Math.max(player.size / 2, Math.min(H - player.size / 2, player.y));

    // Update player trail
    player.trail.push({ x: player.x, y: player.y });
    if (player.trail.length > player.trailLength) {
        player.trail.shift();
    }

    // Update particles
    particles.forEach(p => {
        p.x += Math.cos(p.direction) * p.speed + p.driftX;
        p.y += Math.sin(p.direction) * p.speed + p.driftY;

        // Wrap particles around if they go off-screen
        if (p.x < 0) p.x = W;
        if (p.x > W) p.x = 0;
        if (p.y < 0) p.y = H;
        if (p.y > H) p.y = 0;

        // Subtle blinking effect
        p.blinkTimer += 0.1;
        p.opacity = (Math.sin(p.blinkTimer) * 0.2 + 0.8) * (p.size / 2.5); // Smaller particles blink less dramatically
    });
}

function draw() {
    ctx.clearRect(0, 0, W, H); // Clear canvas for next frame

    // Draw particles
    particles.forEach(p => {
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size / 2, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${p.opacity})`;
        ctx.fill();
    });

    // Draw player trail
    if (player.trail.length > 1) {
        ctx.beginPath();
        ctx.moveTo(player.trail[0].x, player.trail[0].y);
        for (let i = 1; i < player.trail.length; i++) {
            ctx.lineTo(player.trail[i].x, player.trail[i].y);
        }
        ctx.strokeStyle = player.trailColor;
        ctx.lineWidth = player.size * 0.6; // Trail width relative to player size
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
    }

    // Draw player
    ctx.beginPath();
    // A simple triangle for a glider
    // Default angle points right, adjust to point forward based on velocity
    const angle = Math.atan2(player.vy, player.vx); 
    const p1x = player.x + Math.cos(angle) * player.size;
    const p1y = player.y + Math.sin(angle) * player.size;
    const p2x = player.x + Math.cos(angle - Math.PI * 0.75) * player.size * 0.7;
    const p2y = player.y + Math.sin(angle - Math.PI * 0.75) * player.size * 0.7;
    const p3x = player.x + Math.cos(angle + Math.PI * 0.75) * player.size * 0.7;
    const p3y = player.y + Math.sin(angle + Math.PI * 0.75) * player.size * 0.7;

    ctx.moveTo(p1x, p1y);
    ctx.lineTo(p2x, p2y);
    ctx.lineTo(p3x, p3y);
    ctx.closePath();

    ctx.fillStyle = player.color;
    ctx.shadowBlur = 15;
    ctx.shadowColor = 'rgba(100, 150, 255, 0.7)'; // Glow effect
    ctx.fill();
    ctx.shadowBlur = 0; // Reset shadow for other drawings
}

function gameLoop() {
    update();
    draw();
    requestAnimationFrame(gameLoop);
}

// Initialize particles and start game
createParticles();
gameLoop();

