import { useState } from 'react';
import './App.css'; // Keep existing CSS import if any specific styles are needed later

function App() {
  const [score, setScore] = useState(0);
  const [clicksRemaining, setClicksRemaining] = useState(10); // A simple game mechanic: 10 clicks
  const [gameOver, setGameOver] = useState(false);

  const handleClick = () => {
    if (gameOver) return;

    setScore(prevScore => prevScore + 1);
    setClicksRemaining(prevClicks => {
      const newClicks = prevClicks - 1;
      if (newClicks <= 0) {
        setGameOver(true);
      }
      return newClicks;
    });
  };

  const resetGame = () => {
    setScore(0);
    setClicksRemaining(10);
    setGameOver(false);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-900 to-purple-800 flex items-center justify-center p-4">
      <div className="bg-white rounded-xl shadow-2xl p-8 md:p-12 w-full max-w-lg text-center transform hover:scale-105 transition-transform duration-300 ease-in-out">
        <h1 className="text-4xl md:text-5xl font-extrabold text-gray-800 mb-6 animate-pulse">
          Clicker Game!
        </h1>

        <div className="mb-8">
          <p className="text-2xl md:text-3xl text-gray-700 font-semibold">
            Score: <span className="text-indigo-600">{score}</span>
          </p>
          <p className="text-xl md:text-2xl text-gray-600 mt-2">
            Clicks Remaining: <span className="text-purple-600">{clicksRemaining}</span>
          </p>
        </div>

        {!gameOver ? (
          <button
            onClick={handleClick}
            className="bg-gradient-to-r from-blue-500 to-indigo-600 text-white font-bold py-4 px-8 rounded-full shadow-lg hover:from-blue-600 hover:to-indigo-700 active:scale-95 transition-all duration-200 ease-in-out transform hover:-translate-y-1 focus:outline-none focus:ring-4 focus:ring-blue-300"
          >
            Click Me!
          </button>
        ) : (
          <div className="mt-8">
            <p className="text-3xl md:text-4xl font-bold text-red-600 mb-4 animate-bounce">
              Game Over!
            </p>
            <button
              onClick={resetGame}
              className="bg-green-500 text-white font-bold py-3 px-6 rounded-full shadow-md hover:bg-green-600 active:scale-95 transition-all duration-200 ease-in-out focus:outline-none focus:ring-4 focus:ring-green-300"
            >
              Play Again
            </button>
          </div>
        )}

        <p className="text-sm text-gray-500 mt-10">
          A basic web game built with React and Tailwind CSS.
        </p>
      </div>
    </div>
  );
}

export default App;
